accessControlFunction:
function(doc, oldDoc, meta) {
  /* ── Suppression ───────────────────────────────── */
  if (doc._deleted) {
    if (oldDoc) {
      var sid = oldDoc.schoolId;
      if (sid) channel('sch::' + sid);
    }
    return;
  }

  var docType = doc.type || '';

  /* ── Documents globaux → NON syncés (servis via REST) ── */
  var globalTypes = ['config', 'config_modules', 'config_plans', 'config_categories', 'plan', 'module', 'categorie', 'school_group', 'groupe', 'profil'];
  if (globalTypes.indexOf(docType) !== -1) {
    return;
  }

  /* ── Documents opérationnels (school-scoped) ──── */
  var schoolId = doc.schoolId;
  if (!schoolId) {
    throw({forbidden: 'schoolId requis pour type: ' + docType});
  }
  channel('sch::' + schoolId);

  /* ── Validation write ── */
  if (oldDoc && oldDoc.schoolId) {
    requireAccess('sch::' + oldDoc.schoolId);
  }

  /* ── Channel groupe: ONLY for group-level summary documents ──── */
  /* Regular school operational docs stay in sch:: only.            */
  /* ADMIN_GROUPE sees school data via their sch:: channel grants.  */
  var groupSummaryTypes = ['school_summary', 'group_report'];
  if (doc.groupId && groupSummaryTypes.indexOf(docType) !== -1) {
    channel('grp::' + doc.groupId);
  }
}
